+/// Which overlay is currently active.
+#[derive(Clone, Debug)]
+pub enum Overlay {
+    /// Help overlay with keyboard shortcuts.
+    Help(HelpState),
+    /// Command palette for quick actions.
+    Palette(PaletteState),
+    /// Guided tour overlay.
+    Tour(TourState),
+}
